query.sparql:
SELECT ?person ?personLabel WHERE {
  wd:Q761383 wdt:P138 ?person.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?animal ?animalLabel WHERE {
  wd:Q625657 wdt:P7779 ?animal.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?character WHERE {
  ?character wdt:P451 wd:Q4205826.
  ?character wdt:P451 wd:Q4463198.
}

SELECT ?founder ?founderLabel
WHERE {
  ?company wdt:P31 wd:Q4830453;
           wdt:P1478 "Tencent";
           wdt:P199 ?division.
  ?founder wdt:P102 wd:Q200202;
           wdt:P210 ?company.
  ?founder wdt:P463 wd:Q200202.
  ?founder wdt:P39 wd:Q13218629.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?work ?workLabel WHERE {
  ?author wdt:P50 wd:Q1860.
  ?work wdt:P50 ?author; wdt:P1433 wd:Q123456.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?work ?workLabel WHERE {
  ?work wdt:P50 wd:Q198572;  # Replace wd:Q198572 with the actual Wikidata entity for the author
        wdt:P6333 ?broaderWork.
  FILTER(?broaderWork != wd:Q198572)  # Exclude the Witcher series
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?state WHERE {
  {
    wd:Q123456 wdt:P276 ?state.
    wd:Q789012 wdt:P276 ?state.
  }
}

SELECT ?school ?schoolLabel WHERE {
  wd:Q231121 wdt:P69 ?school.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}
